// src/pages/dashboard/ContentDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import NavBar from "../../components/NavBar";

function ContentDashboard() {
  return (
    <Layout pageTitle="Content Creator Dashboard - NexaLearn LMS">
      <NavBar />
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          gap: "25px",
        }}
      >
        <h1 style={{ color: "#059669", fontWeight: "700", fontSize: "1.8rem" }}>
          Content Creator Dashboard
        </h1>

        <div
          style={{
            padding: "30px",
            borderRadius: "12px",
            backgroundColor: "#f0fdf4",
            boxShadow: "0 6px 18px rgba(0,0,0,0.08)",
          }}
        >
          <h5 style={{ marginBottom: "15px", fontWeight: "600" }}>
            Create and Manage Content
          </h5>
          <p style={{ color: "#065f46", lineHeight: "1.6" }}>
            Upload new course materials, update existing content, and track content
            performance. Ensure educational quality and student engagement.
          </p>
          <button
            style={{
              backgroundColor: "#059669",
              color: "#fff",
              border: "none",
              padding: "12px 20px",
              borderRadius: "6px",
              fontWeight: "600",
              cursor: "pointer",
              transition: "background-color 0.3s ease",
            }}
            onMouseOver={(e) => (e.target.style.backgroundColor = "#047857")}
            onMouseOut={(e) => (e.target.style.backgroundColor = "#059669")}
          >
            Create New Content
          </button>
        </div>
      </div>
    </Layout>
  );
}

export default ContentDashboard;
